patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index fdadf729fbd5..563e3c6fabd9 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8040,6 +8040,17 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
     }
   }

+  // fcmp oeq/une (select Cond, X, (fneg X)), 0.0 --> fcmp oeq/une X, 0.0
+  if (match(Op1, m_AnyZeroFP()) && (Pred == FCmpInst::FCMP_OEQ || Pred == FCmpInst::FCMP_UNE || Pred == FCmpInst::FCMP_UEQ || Pred == FCmpInst::FCMP_ONE)) {
+    Value *Cond;
+    if (match(Op0, m_Select(m_Value(Cond), m_Value(X), m_FNeg(m_Value()))) &&
+        match(Op0, m_Select(m_Value(Cond), m_Value(X), m_FNeg(m_Specific(X)))))
+      return new FCmpInst(Pred, X, Op1, "", &I);
+    if (match(Op0, m_Select(m_Value(Cond), m_FNeg(m_Value()), m_Value(X))) &&
+        match(Op0, m_Select(m_Value(Cond), m_FNeg(m_Specific(X)), m_Specific(X))))
+      return new FCmpInst(Pred, X, Op1, "", &I);
+  }
+
   // Handle fcmp with instruction LHS and constant RHS.
   Instruction *LHSI;
   Constant *RHSC;

